record_types.code:
type anon_anon_87 (discr : unsigned := 0) is record
   case discr is
      when 0 =>
         work_void : System
           .Address;
      when 1 =>
         work_int : access int;
      when others =>
         work_atomic : access double;
   end case;
end record;

type gsl_spmatrix is record
   size1 : aliased size_t;
   size2 : aliased size_t;
   i     : access int;
   data  : access double;
   p     : access int;
   nzmax : aliased size_t;
   nz    : aliased size_t;
   tree  : access gsl.bst
     .gsl_bst_workspace;
   node_size : aliased size_t;
   work : aliased anon_anon_87;
   sptype    : aliased int;
   spflags : aliased size_t;
end record;
